import React, { useRef, useState } from 'react';
import springLogo from '../../assets/with_Spring_removebg.png';
import useClickOutside from '../../hooks/common/useClickOutside';

const UserHeader = () => {

    const [isDropdownOpen, setIsDropdownOpen] = useState(false);
    const dropdownRef = useRef(null);

    useClickOutside(dropdownRef, () => {
        if(isDropdownOpen) setIsDropdownOpen(false);
    });

    const toggleDropdown = (e) => {
        // e.preventDefault();
        setIsDropdownOpen(!isDropdownOpen);
    };

    return(
        <header className="w-full h-72 bg-sky-400 flex items-start">
            <div className="container mx-auto px-4 flex items-center mt-20">
                <span className="flex-shrink-0">
                    <img src={springLogo} alt="Spring 로고" className="h-44 w-44 object-contain mr-5"/>
                </span>
                <span className="ml-4 flex-grow">
                    <form className="w-full max-w-2xl mx-auto">
                        <div className="flex relative" ref={dropdownRef}>
                            <button id="dropdown-button" onClick={toggleDropdown} className="flex-shrink-0 z-10 inline-flex items-center py-2.5 px-4 text-sm font-medium text-center text-gray-900 bg-gray-100 border border-gray-300 rounded-l-lg hover:bg-gray-200 focus:ring-4 focus:outline-none focus:ring-gray-100 dark:bg-gray-700 dark:hover:bg-gray-600 dark:focus:ring-gray-700 dark:text-white dark:border-gray-600" type="button">통합검색
                                <svg className="w-2.5 h-2.5 ms-2.5" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 10 6">
                                <path stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="m1 1 4 4 4-4"/>
                                </svg>
                            </button>
                            {isDropdownOpen && (
                                <div id="dropdown" className="absolute top-full left-0 z-10 bg-white divide-y divide-gray-100 rounded-lg shadow w-44">
                                <ul className="py-2 text-sm text-gray-700 dark:text-gray-200" aria-labelledby="dropdown-button">
                                    <li>
                                        <button type="button" className="inline-flex w-full px-4 py-2 hover:bg-gray-100">Mockups</button>
                                    </li>
                                    <li>
                                        <button type="button" className="inline-flex w-full px-4 py-2 hover:bg-gray-100">Templates</button>
                                    </li>
                                    <li>
                                        <button type="button" className="inline-flex w-full px-4 py-2 hover:bg-gray-100">Design</button>
                                    </li>
                                    <li>
                                        <button type="button" className="inline-flex w-full px-4 py-2 hover:bg-gray-100">Logos</button>
                                    </li>
                                </ul>
                            </div>
                            )}
                            <div className="relative w-full">
                                <input type="search" id="search-dropdown" name="allSearch" className="block p-2.5 w-full z-20 xl:w-128 text-sm text-gray-900 bg-gray-50 rounded-r-lg border-l-gray-50 border-l-2 border border-gray-300 focus:ring-blue-500 focus:border-blue-500 dark:bg-gray-700 dark:border-s-gray-700  dark:border-gray-600 dark:placeholder-gray-400 dark:text-white dark:focus:border-blue-500" placeholder="Search Mockups, Logos, Design Templates..." required />
                                <button type="submit" className="absolute top-0 right-0 p-2.5 text-sm font-medium h-full text-gray-600 bg-transparent rounded-r-lg border focus:ring-4 focus:outline-none">
                                    <svg className="w-4 h-4" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 20 20">
                                        <path stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="m19 19-4-4m0-7A7 7 0 1 1 1 8a7 7 0 0 1 14 0Z"/>
                                    </svg>
                                    <span className="sr-only">Search</span>
                                </button>
                            </div>
                        </div>
                    </form>
                </span>
            </div>

        </header>

    )


}

export default UserHeader;
